'use client';

import { useCallback, useRef, useState } from 'react';

interface ChatComposerProps {
  onSend: (text: string) => void;
  onPlusClick: () => void;
  onMicClick: () => void;
  disabled: boolean;
  isListening: boolean;
}

export function ChatComposer({ onSend, onPlusClick, onMicClick, disabled, isListening }: ChatComposerProps) {
  const [text, setText] = useState('');
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const handleSend = useCallback(() => {
    const trimmed = text.trim();
    if (!trimmed || disabled) return;
    onSend(trimmed);
    setText('');
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
    }
  }, [text, disabled, onSend]);

  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  }, [handleSend]);

  const handleChange = useCallback((e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setText(e.target.value);
    const ta = e.target;
    ta.style.height = 'auto';
    ta.style.height = Math.min(ta.scrollHeight, 160) + 'px';
  }, []);

  return (
    <div className="px-4 pb-4 pt-2 shrink-0 border-t border-violet-900/30 bg-black/20 backdrop-blur-sm">
      <div className="flex items-end gap-2 bg-black/50 border border-violet-800/40 rounded-2xl px-3 py-2 focus-within:border-violet-600/60 transition-colors">
        {/* Plus button */}
        <button
          onClick={onPlusClick}
          className="p-1.5 rounded-lg text-violet-400 hover:text-violet-200 hover:bg-violet-900/30 transition-colors shrink-0 mb-0.5"
          aria-label="More actions"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 4v16m8-8H4" />
          </svg>
        </button>

        {/* Textarea */}
        <textarea
          ref={textareaRef}
          value={text}
          onChange={handleChange}
          onKeyDown={handleKeyDown}
          placeholder={disabled ? 'OmegA is thinking…' : 'Message OmegA…'}
          disabled={disabled}
          rows={1}
          className="flex-1 bg-transparent text-sm text-slate-100 placeholder-violet-600 resize-none outline-none leading-6 max-h-40 py-1 disabled:opacity-50"
          style={{ scrollbarWidth: 'none' }}
        />

        {/* Mic button */}
        <button
          onClick={onMicClick}
          className={`p-1.5 rounded-lg transition-colors shrink-0 mb-0.5 ${
            isListening
              ? 'text-red-400 bg-red-950/40 hover:bg-red-900/40 animate-pulse'
              : 'text-violet-400 hover:text-violet-200 hover:bg-violet-900/30'
          }`}
          aria-label={isListening ? 'Stop listening' : 'Start voice input'}
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
          </svg>
        </button>

        {/* Send button */}
        <button
          onClick={handleSend}
          disabled={!text.trim() || disabled}
          className="p-1.5 rounded-lg bg-violet-700 hover:bg-violet-600 disabled:opacity-30 disabled:cursor-not-allowed text-white transition-colors shrink-0 mb-0.5"
          aria-label="Send message"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
          </svg>
        </button>
      </div>
      <p className="text-center text-violet-800 text-xs mt-2">
        OmegA · Sovereign Intelligence
      </p>
    </div>
  );
}

